def gen(rng, size):
    n = max(1, min(size, 300))
    vals = rng.sample(range(-3000, 3001), n)
    def build(vs):
        if not vs:
            return None
        i = rng.randrange(len(vs))
        return (vs[i], build(vs[:i]), build(vs[i+1:]))
    root = build(vals)
    ino, post = [], []
    def io(t):
        if t is None:
            return
        io(t[1]); ino.append(t[0]); io(t[2])
    def po(t):
        if t is None:
            return
        po(t[1]); po(t[2]); post.append(t[0])
    io(root); po(root)
    return [ino, post]

