class Solution:
    def buildTree(self, inorder, postorder):
        def build(ino, post):
            if not post:
                return None
            root_val = post[-1]
            k = ino.index(root_val)
            node = TreeNode(root_val)
            node.left = build(ino[:k], post[:k])
            node.right = build(ino[k + 1:], post[k:-1])
            return node
        return build(inorder, postorder)

